/* CAN Bus Driver API - can_driver.h */
#ifndef CAN_DRIVER_H
#define CAN_DRIVER_H

#include <stdint.h>

typedef struct {
    uint32_t id;
    uint8_t  ide;        /* 0=standard, 1=extended */
    uint8_t  rtr;
    uint8_t  dlc;
    uint8_t  data[8];
} CAN_Frame_t;

typedef void (*CAN_RxCallback_t)(CAN_Frame_t *frame);

typedef struct {
    uint32_t         baudrate;
    CAN_RxCallback_t rx_callback;
    uint8_t          tx_queue_depth;
    uint8_t          rx_queue_depth;
} CAN_Config_t;

int  CAN_Init(uint8_t channel, CAN_Config_t *config);
int  CAN_Transmit(uint8_t channel, CAN_Frame_t *frame);
void CAN_SetFilter(uint8_t channel, uint32_t id, uint32_t mask);
void CAN_Deinit(uint8_t channel);

#endif /* CAN_DRIVER_H */

